import React, { useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { Button } from "antd";
import { FolderTree, Save, ArrowLeft, ChevronRight, Layers, ShieldCheck, Cpu } from "lucide-react";
import { getCategories } from "../features/pcategory/pcategorySlice";
import {
  createSubCategory,
  getAProductSubCategory,
  resetState,
  updateAProductSubCategory,
} from "../features/pSubCategory/pSubCategorySlice";

let schema = yup.object().shape({
  title: yup.string().required("Subcategory Name is Required"),
  pcategory: yup.string().required("Parent Category is Required"),
});

export default function AddSubCat() {
  const dispatch = useDispatch();
  const location = useLocation();
  const getpSubCatId = location.pathname.split("/")[3];
  const navigate = useNavigate();

  const newCategory = useSelector((state) => state.pSubcategory);
  const {
    isSuccess,
    isError,
    isLoading,
    createdSubCategory,
    subCategoryName, // Note: Use subCategoryName from slice
    updatedSubCategory,
  } = newCategory;

  const pCatStat = useSelector((state) => state.pCategory.pCategories);

  useEffect(() => {
    dispatch(getCategories());
    if (getpSubCatId !== undefined) {
      dispatch(getAProductSubCategory(getpSubCatId));
    } else {
      dispatch(resetState());
    }
  }, [getpSubCatId, dispatch]);

  useEffect(() => {
    if (isSuccess && createdSubCategory) {
      toast.success("Branch Initialized: Sub-Registry Updated");
      dispatch(resetState());
      navigate("../list-subcategory");
    }
    if (isSuccess && updatedSubCategory) {
      toast.success("Archetype Revised: Configuration Persistent");
      dispatch(resetState());
      navigate("../list-subcategory");
    }
    if (isError) {
      toast.error("Network Exception: Propagation Failed");
    }
  }, [isSuccess, isError, isLoading, navigate, createdSubCategory, updatedSubCategory, dispatch]);

  const formik = useFormik({
    enableReinitialize: true,
    initialValues: {
      title: subCategoryName || "",
      pcategory: "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      if (getpSubCatId !== undefined) {
        dispatch(
          updateAProductSubCategory({ id: getpSubCatId, subCategoryData: values })
        );
      } else {
        dispatch(createSubCategory(values));
      }
    },
  });

  return (
    <div className="min-h-screen pb-20 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      {/* Command Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-12">
        <div className="space-y-3">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-2 h-2 rounded-full bg-cyan-600 animate-ping" />
            <span className="text-[11px] font-black text-cyan-600 uppercase tracking-[0.4em]">
              {getpSubCatId !== undefined ? "Archetype Revision" : "Branch Initialization"}
            </span>
          </div>
          <h1 className="text-[48px] md:text-[64px] font-black text-slate-900 tracking-tighter leading-[0.9] italic">
            {getpSubCatId !== undefined ? "Modify" : "Create"} <span className="text-cyan-600">Sub-Category</span>
          </h1>
          <p className="text-[16px] text-slate-400 font-bold max-w-xl leading-relaxed">
            Expanding the commercial ontology with secondary nodes and child-registry associations.
          </p>
        </div>

        <Button
          onClick={() => navigate(-1)}
          icon={<ArrowLeft size={18} />}
          className="h-14 px-8 flex items-center gap-3 rounded-[22px] border-none bg-slate-50 hover:bg-slate-100 text-slate-500 font-black uppercase text-[11px] tracking-widest shadow-sm hover:shadow-md transition-all active:scale-95"
        >
          Abort Protocol
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        <div className="lg:col-span-8">
          <div className="enterprise-card p-8 md:p-12 overflow-hidden relative">
            <div className="absolute top-0 right-0 w-64 h-64 bg-cyan-500/5 rounded-full blur-3xl -mr-32 -mt-32" />
            
            <form onSubmit={formik.handleSubmit} className="space-y-10 relative z-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Parent Domain Selection */}
                <div className="space-y-4">
                  <div className="flex items-center gap-3 mb-2">
                    <Layers size={18} className="text-slate-400" />
                    <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Parent Domain</span>
                  </div>
                  <select
                    name="pcategory"
                    onChange={formik.handleChange("pcategory")}
                    onBlur={formik.handleBlur("pcategory")}
                    value={formik.values.pcategory}
                    className="w-full h-16 px-6 bg-slate-50 border-2 border-slate-50 rounded-[22px] text-[15px] font-bold focus:outline-none focus:border-cyan-500 focus:bg-white transition-all appearance-none cursor-pointer"
                  >
                    <option value="">Select Domain...</option>
                    {pCatStat.map((i, j) => (
                      <option key={j} value={i._id}>{i.title}</option>
                    ))}
                  </select>
                  {formik.touched.pcategory && formik.errors.pcategory && (
                    <p className="text-rose-500 text-[10px] uppercase font-black tracking-widest pl-4">
                      {formik.errors.pcategory}
                    </p>
                  )}
                </div>

                {/* Sub-Node Identity */}
                <div className="space-y-4">
                  <div className="flex items-center gap-3 mb-2">
                    <FolderTree size={18} className="text-slate-400" />
                    <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Sub-Node Identity</span>
                  </div>
                  <input
                    type="text"
                    name="title"
                    onChange={formik.handleChange("title")}
                    onBlur={formik.handleBlur("title")}
                    value={formik.values.title}
                    placeholder="Enter Archetype Name..."
                    className="w-full h-16 px-6 bg-slate-50 border-2 border-slate-50 rounded-[22px] text-[15px] font-bold focus:outline-none focus:border-cyan-500 focus:bg-white transition-all shadow-sm"
                  />
                  {formik.touched.title && formik.errors.title && (
                    <p className="text-rose-500 text-[10px] uppercase font-black tracking-widest pl-4">
                      {formik.errors.title}
                    </p>
                  )}
                </div>
              </div>

              <div className="pt-8 border-t border-slate-50">
                  <Button
                    type="primary"
                    htmlType="submit"
                    loading={isLoading}
                    size="large"
                    icon={<Save size={20} />}
                    className="bg-slate-900 hover:bg-cyan-600 rounded-[28px] h-20 font-black text-[13px] uppercase tracking-[0.25em] shadow-2xl shadow-slate-900/20 hover:shadow-cyan-500/40 border-none transition-all w-full flex items-center justify-center gap-4 group active:scale-[0.97]"
                  >
                    {getpSubCatId !== undefined ? "Commit Extension Revision" : "Initialize Sub-Domain Node"}
                  </Button>
              </div>
            </form>
          </div>

          <div className="mt-8 flex items-center justify-center gap-3 opacity-30 grayscale hover:grayscale-0 transition-all duration-500">
             <ShieldCheck size={16} />
             <span className="text-[10px] font-black uppercase tracking-[0.3em]">Encrypted Pulse Core Transmission</span>
          </div>
        </div>

        {/* Intelligence Report */}
        <div className="lg:col-span-4 space-y-6">
           <div className="enterprise-card p-10 bg-slate-900 text-white border-none shadow-2xl shadow-slate-900/30 relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-48 h-48 bg-cyan-500/20 rounded-full blur-3xl -mr-24 -mt-24 group-hover:bg-cyan-500/30 transition-all duration-700" />
              <div className="relative z-10 space-y-8">
                 <div className="w-14 h-14 rounded-2xl bg-white/10 flex items-center justify-center backdrop-blur-md">
                    <Cpu size={28} className="text-cyan-400" />
                 </div>
                 <div>
                    <h4 className="text-[20px] font-black italic tracking-tighter mb-2">Protocol Brief</h4>
                    <p className="text-slate-400 font-bold text-[14px] leading-relaxed">
                      Sub-categories provide granular stratification. Each sub-node must inherit parameters from its parent commercial domain.
                    </p>
                 </div>
                 <div className="space-y-4">
                    <div className="flex items-center gap-3 p-4 rounded-2xl bg-white/5 border border-white/5">
                       <ChevronRight size={14} className="text-cyan-500" />
                       <span className="text-[11px] font-black uppercase tracking-widest text-slate-300">Semantic Linkage Level 2</span>
                    </div>
                    <div className="flex items-center gap-3 p-4 rounded-2xl bg-white/5 border border-white/5">
                       <ChevronRight size={14} className="text-cyan-500" />
                       <span className="text-[11px] font-black uppercase tracking-widest text-slate-300">Ontological Verification Sync</span>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        .enterprise-card {
            background: #ffffff;
            border-radius: 40px;
            border: 1.5px solid #f8fafc;
            box-shadow: 0 15px 40px rgba(0,0,0,0.02);
            transition: all 0.6s cubic-bezier(0.2, 1, 0.2, 1);
        }
      `}</style>
    </div>
  );
}
